challenges.code:
.card {
  position: relative;
  transition: left 0.25s ease-out, width 0.25s ease-out;
}

.card:hover {
  left: -6px;
  width: 102%;
}

challenges.codeTemplate:
@keyframes slide-in {
  from { opacity: 0; {{blank}}: translateY(24px); }
  to   { opacity: 1; {{blank}}: translateY(0);    }
}

.card {
  animation: slide-in 0.4s ease-out forwards;
}

challenges.code:
@keyframes pulse {
  0%, 100% { transform: scale(1);    opacity: 1;   }
  50%      { transform: scale(1.08); opacity: 0.75; }
}

.badge {
  animation: pulse 1.6s ease-in-out infinite;
}
